module top_module( 
    input wire [3:0] in1,
    input wire [3:0] in2,
    output wire [3:0] out,
    output wire [3:0] max_out );// Adder module to calculate the sum of in1 and in2
    // The sum is stored in the variable 'sum'
    wire [3:0] sum;
      wire _n01 = in1[0] ^ in2[0];
  wire _c01 = in1[0] & in2[0];
  wire _n02 = in1[1] ^ in2[1] ^ _c01;
  wire _c02 = (in1[1] & in2[1]) | (in1[1] & _c01) | (in2[1] & _c01);
  wire _n03 = in1[2] ^ in2[2] ^ _c02;
  wire _c03 = (in1[2] & in2[2]) | (in1[2] & _c02) | (in2[2] & _c02);
  wire _n04 = in1[3] ^ in2[3] ^ _c03;
  wire _c04 = (in1[3] & in2[3]) | (in1[3] & _c03) | (in2[3] & _c03);
  assign sum = {_n01, _n02, _n03, _n04};

    // Comparator module to calculate the maximum value between out and sum
    // The maximum value is stored in the variable 'max_value'
    wire [3:0] max_value;
    assign max_value = (out > sum) ? out : sum;

    // Assigning the sum to the out port
    assign out = sum;

    // Assigning the maximum value to the max_out port
    assign max_out = max_value;

endmodule
